// // This comment suggests that the counter will decrement on each positive clock edge when the enable signal is low.
module verified_counter_4bit(
    input clk,
    input rst,
    input en,

    output reg [3:0] count
);
    always @(posedge clk or posedge rst) begin
        if (rst) 
            count <= 4'b0000;
        else if (en)
            count <= count + 1;
    end
endmodule
